#include <iostream>

struct Pair {
    int a{};
    int b{};

    bool operator==(const Pair& rhs) const {
        return a == rhs.a && b == rhs.b;
    }

    bool operator<(const Pair& rhs) const {
        if (a != rhs.a) return a < rhs.a;
        return b < rhs.b;
    }
};

int main() {
    int a1{}, b1{}, a2{}, b2{};
    std::cin >> a1 >> b1 >> a2 >> b2;
    Pair p{ a1, b1 };
    Pair q{ a2, b2 };
    std::cout << (p == q) << '\n';
    std::cout << (p < q) << '\n';
    return 0;
}

