solution_code:
#include <iostream>

struct TempRange {
    int low{};
    int high{};

    bool operator<(const TempRange& rhs) const {
        return low < rhs.low;
    }

    bool contains(int value) const {
        return value >= low && value <= high;
    }
};

int main() {
    int low{}, high{}, temp{};
    std::cin >> low >> high >> temp;
    TempRange range{ low, high };
    std::cout << (range.contains(temp) ? "in range" : "out of range") << '\n';
    return 0;
}
